--- packages/ui/src/engine/pixel-characters.ts	2024-06-01 00:00:00.000000000 +0000
+++ packages/ui/src/engine/pixel-characters.ts	2024-06-01 00:00:00.000000000 +0000
@@ 1031,20 +1031,94 @@
-function drawTiledFloor(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
-  const ft: Record<CharacterType, string> = {
-    king: 'carpet', nobility: 'wood', knight: 'wood', squire: 'wood',
-    healer: 'dark_stone', sentinel: 'stone', scribe: 'wood', judge: 'wood', blacksmith: 'stone',
-  };
-  const tile = 16;
-  const kind = ft[type];
-
-  if (kind === 'wood') {
-    const cols = ['#3e2a18', '#4a3420', '#3a2614', '#443018'];
-    ctx.fillStyle = '#3e2a18'; ctx.fillRect(x, y, w, h);
-    const pW = 28;
-    for (let r = 0; r < Math.ceil(h / tile); r++) {
-      for (let c = 0; c < Math.ceil(w / pW) + 1; c++) {
-        const px = x + c * pW + (r % 2) * (pW / 2);
-        ctx.fillStyle = cols[(c + r * 3) % cols.length];
-        ctx.fillRect(px + 1, y + r * tile + 1, pW - 1, tile - 1);
-        ctx.fillStyle = 'rgba(0,0,0,0.08)';
-        ctx.fillRect(px + 4, y + r * tile + 3, pW - 8, 1);
-        ctx.fillRect(px + 6, y + r * tile + 7, pW - 10, 1);
-        ctx.fillRect(px + 3, y + r * tile + 11, pW - 6, 1);
-      }
-      ctx.fillStyle = 'rgba(0,0,0,0.15)';
-      ctx.fillRect(x, y + r * tile, w, 1);
-    }
-  } else if (kind === 'stone' || kind === 'dark_stone') {
-    const bc = kind === 'dark_stone' ? '#1a2030' : '#2c3040';
-    const lc = kind === 'dark_stone' ? '#222838' : '#343848';
-    ctx.fillStyle = bc; ctx.fillRect(x, y, w, h);
-    for (let r = 0; r < Math.ceil(h / tile); r++) {
-      for (let c = 0; c < Math.ceil(w / tile); c++) {
-        const tx = x + c * tile, ty = y + r * tile;
-        const hash = ((c * 17 + r * 31) & 0xFF) / 255;
-        ctx.fillStyle = hash > 0.5 ? lc : bc;
-        ctx.fillRect(tx + 1, ty + 1, tile - 2, tile - 2);
-        if (hash > 0.85) {
-          ctx.fillStyle = 'rgba(0,0,0,0.2)';
-          ctx.fillRect(tx + 4, ty + 6, 8, 1);
-          ctx.fillRect(tx + 7, ty + 4, 1, 6);
-        }
-      }
-    }
-  } else if (kind === 'carpet') {
-    ctx.fillStyle = '#2c3040'; ctx.fillRect(x, y, w, h);
-    for (let c = 0; c < Math.ceil(w / tile); c++)
-      for (let r = 0; r < Math.ceil(h / tile); r++) {
-        ctx.fillStyle = ((c + r) % 2 === 0) ? '#303848' : '#282e3e';
-        ctx.fillRect(x + c * tile, y + r * tile, tile, tile);
-      }
-    const cw = w * 0.35, cx = x + (w - cw) / 2;
-    ctx.fillStyle = '#6b1515'; ctx.fillRect(cx, y, cw, h);
-    ctx.fillStyle = '#8b2020'; ctx.fillRect(cx + 3, y, cw - 6, h);
-    ctx.fillStyle = P.gold[2];
-    ctx.fillRect(cx + 1, y, 2, h);
-    ctx.fillRect(cx + cw - 3, y, 2, h);
-    for (let dy = 0; dy < h; dy += 20) {
-      ctx.fillStyle = P.gold[1];
-      ctx.fillRect(cx + cw / 2 - 2, y + dy + 6, 4, 4);
-    }
-  }
+function drawTiledFloor(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
+  const tile = 16;
+  // Define tilemaps for each floor type with varied patterns
+  type FloorTile = (ctx: CanvasRenderingContext2D, x: number, y: number, size: number) => void;
+
+  // Stone tile variants with cracks and color variations
+  const stoneTiles: FloorTile[] = [
+    (ctx, x, y, s) => {
+      ctx.fillStyle = '#2c3040';
+      ctx.fillRect(x, y, s, s);
+      ctx.strokeStyle = '#343848';
+      ctx.lineWidth = 1;
+      ctx.beginPath();
+      ctx.moveTo(x + 2, y + 2);
+      ctx.lineTo(x + s - 3, y + s - 3);
+      ctx.stroke();
+    },
+    (ctx, x, y, s) => {
+      ctx.fillStyle = '#2f3243';
+      ctx.fillRect(x, y, s, s);
+      ctx.strokeStyle = '#3a3e50';
+      ctx.lineWidth = 1;
+      ctx.beginPath();
+      ctx.moveTo(x + s / 2, y + 2);
+      ctx.lineTo(x + s / 2, y + s - 3);
+      ctx.moveTo(x + 2, y + s / 2);
+      ctx.lineTo(x + s - 3, y + s / 2);
+      ctx.stroke();
+    },
+    (ctx, x, y, s) => {
+      ctx.fillStyle = '#2a2e3e';
+      ctx.fillRect(x, y, s, s);
+      ctx.strokeStyle = '#383c4d';
+      ctx.lineWidth = 1;
+      ctx.beginPath();
+      ctx.moveTo(x + 3, y + s / 3);
+      ctx.lineTo(x + s - 4, y + s / 3);
+      ctx.moveTo(x + 3, y + s * 2 / 3);
+      ctx.lineTo(x + s - 4, y + s * 2 / 3);
+      ctx.stroke();
+    },
+  ];
+
+  // Dark stone tiles (for healer)
+  const darkStoneTiles: FloorTile[] = [
+    (ctx, x, y, s) => {
+      ctx.fillStyle = '#1a2030';
+      ctx.fillRect(x, y, s, s);
+      ctx.strokeStyle = '#222838';
+      ctx.lineWidth = 1;
+      ctx.beginPath();
+      ctx.moveTo(x + 3, y + 3);
+      ctx.lineTo(x + s - 4, y + s - 4);
+      ctx.stroke();
+    },
+    (ctx, x, y, s) => {
+      ctx.fillStyle = '#1c2235';
+      ctx.fillRect(x, y, s, s);
+      ctx.strokeStyle = '#262c3f';
+      ctx.lineWidth = 1;
+      ctx.beginPath();
+      ctx.moveTo(x + s / 2, y + 2);
+      ctx.lineTo(x + s / 2, y + s - 3);
+      ctx.moveTo(x + 2, y + s / 2);
+      ctx.lineTo(x + s - 3, y + s / 2);
+      ctx.stroke();
+    },
+  ];
+
+  // Wood tile variants with grain and color variations
+  const woodTiles: FloorTile[] = [
+    (ctx, x, y, s) => {
+      ctx.fillStyle = '#3e2a18';
+      ctx.fillRect(x, y, s, s);
+      ctx.fillStyle = '#4a3420';
+      for (let i = 2; i < s; i += 4) {
+        ctx.fillRect(x + i, y + 1, 1, s - 2);
+      }
+    },
+    (ctx, x, y, s) => {
+      ctx.fillStyle = '#4a3420';
+      ctx.fillRect(x, y, s, s);
+      ctx.fillStyle = '#3a2614';
+      for (let i = 1; i < s; i += 3) {
+        ctx.fillRect(x + i, y + 2, 1, s - 4);
+      }
+    },
+    (ctx, x, y, s) => {
+      ctx.fillStyle = '#443018';
+      ctx.fillRect(x, y, s, s);
+      ctx.fillStyle = '#3e2a18';
+      for (let i = 3; i < s; i += 5) {
+        ctx.fillRect(x + i, y + 1, 1, s - 2);
+      }
+    },
+  ];
+
+  // Carpet tile pattern
+  const carpetTile: FloorTile = (ctx, x, y, s) => {
+    ctx.fillStyle = '#303848';
+    ctx.fillRect(x, y, s, s);
+    ctx.fillStyle = '#282e3e';
+    ctx.fillRect(x + s / 2, y, s / 2, s / 2);
+    ctx.fillRect(x, y + s / 2, s / 2, s / 2);
+  };
+
+  // Select tile set based on room type
+  let tiles: FloorTile[] = [];
+  let baseColor = '#000000';
+  switch (type) {
+    case 'king':
+      baseColor = '#2c3040';
+      tiles = [carpetTile];
+      break;
+    case 'nobility':
+    case 'knight':
+    case 'squire':
+    case 'scribe':
+    case 'judge':
+      baseColor = '#3e2a18';
+      tiles = woodTiles;
+      break;
+    case 'healer':
+      baseColor = '#1a2030';
+      tiles = darkStoneTiles;
+      break;
+    case 'sentinel':
+    case 'blacksmith':
+      baseColor = '#2c3040';
+      tiles = stoneTiles;
+      break;
+    default:
+      baseColor = '#3e2a18';
+      tiles = woodTiles;
+      break;
+  }
+
+  ctx.fillStyle = baseColor;
+  ctx.fillRect(x, y, w, h);
+
+  const cols = Math.ceil(w / tile);
+  const rows = Math.ceil(h / tile);
+  for (let r = 0; r < rows; r++) {
+    for (let c = 0; c < cols; c++) {
+      const tx = x + c * tile;
+      const ty = y + r * tile;
+      // Choose tile variant based on position hash for variation
+      const idx = (c * 31 + r * 17) % tiles.length;
+      tiles[idx](ctx, tx, ty, tile);
+    }
+  }
+}
